  import type { SkillContext, SkillResult } from '@mariozechner/pi-coding-agent';                                         

  /**                                                                                                                     
   * Skill: gistCommentReview                                                                                             
   *                                                                                                                      
   * Parameters                                                                                                           
   * ├─ gistUrl: string  – Full GitHub Gist URL (e.g. https://gist.github.com/…/1234abcd)                                 
