      typeof lastComment.body === 'string' ? lastComment.body : '';                                                       

    /* ------------------------------------------------------------------ */                                              
    /* 4️⃣ Return the comment body and a short summary                    */                                               
    /* ------------------------------------------------------------------ */                                              
    return {                                                                                                              
      text: body,                                                                                                         
      summary: `Fetched ${comments.length} comment(s); last comment (ID ${lastComment.id})`,                              
    };                                                                                                                    
  }
